#include <stdio.h>
#include <string.h>
#include <stdlib.h>

typedef struct {char title[105]; char artist[105]; int duration;} Song;

static Song *songs = NULL;
static int song_cnt = 0;
static int song_cap = 0;

void ensure_capacity(){
    if(song_cnt>=song_cap){
        song_cap = song_cap? song_cap*2 : 16;
        songs = realloc(songs, song_cap*sizeof(Song));
    }
}

void add_song(const char *title,const char *artist,int dur){
    ensure_capacity();
    strncpy(songs[song_cnt].title,title,104); songs[song_cnt].title[104]='\0';
    strncpy(songs[song_cnt].artist,artist,104); songs[song_cnt].artist[104]='\0';
    songs[song_cnt].duration=dur;
    song_cnt++;
}

void remove_song(const char *title){
    int i,j=0;
    for(i=0;i<song_cnt;i++){
        if(strcmp(songs[i].title,title)!=0){
            if(i!=j){songs[j]=songs[i];}
            j++;
        }
    }
    song_cnt=j;
}

int total_duration(){
    int sum=0,i;
    for(i=0;i<song_cnt;i++) sum+=songs[i].duration;
    return sum;
}

void display(){
    int i;
    for(i=0;i<song_cnt;i++){
        int m = songs[i].duration/60;
        int s = songs[i].duration%60;
        printf("%d. %s by %s - %d:%02d\n", i+1, songs[i].title, songs[i].artist, m, s);
    }
}

void clear_playlist(){
    song_cnt=0;
}

int main(){
    char line[256];
    int T;
    if(!fgets(line, sizeof(line), stdin)) return 0;
    T = atoi(line);
    while(T--){
        while(fgets(line, sizeof(line), stdin)){
            line[strcspn(line,"\n")]=0; // strip newline
            if(strcmp(line,"exit")==0) break;
            if(strcmp(line,"add")==0){
                char data[256];
                fgets(data,sizeof(data),stdin);
                data[strcspn(data,"\n")]=0;
                char *title=strtok(data,";");
                char *artist=strtok(NULL,";");
                char *durstr=strtok(NULL,";");
                add_song(title,artist,atoi(durstr));
            } else if(strcmp(line,"remove")==0){
                char title[105];
                fgets(title,sizeof(title),stdin);
                title[strcspn(title,"\n")]=0;
                remove_song(title);
            } else if(strcmp(line,"duration")==0){
                printf("%d\n", total_duration());
            } else if(strcmp(line,"display")==0){
                display();
            }
        }
        clear_playlist();
    }
    free(songs);
    return 0;
}

