import java.io.*;
import java.util.*;

public class Main {
    static class Song {
        String title, artist; int duration;
        Song(String t,String a,int d){title=t;artist=a;duration=d;}
    }
    static List<Song> songs = new ArrayList<>();
    static void addSong(String t,String a,int d){songs.add(new Song(t,a,d));}
    static void removeSong(String t){
        songs.removeIf(s->s.title.equals(t));
    }
    static int totalDuration(){
        int sum=0; for(Song s: songs) sum+=s.duration; return sum;
    }
    static void display(PrintWriter out){
        for(int i=0;i<songs.size();i++){
            Song s=songs.get(i);
            int m=s.duration/60, sec=s.duration%60;
            out.printf("%d. %s by %s - %d:%02d\n", i+1, s.title, s.artist, m, sec);
        }
    }
    static void clear(){songs.clear();}
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter out = new PrintWriter(new BufferedWriter(new OutputStreamWriter(System.out)));
        int T = Integer.parseInt(br.readLine().trim());
        while(T-- > 0){
            String line;
            while((line = br.readLine()) != null){
                line = line.trim();
                if(line.equals("exit")) break;
                switch(line){
                    case "add":
                        String data = br.readLine();
                        String[] parts = data.split(";");
                        addSong(parts[0], parts[1], Integer.parseInt(parts[2]));
                        break;
                    case "remove":
                        String title = br.readLine();
                        removeSong(title);
                        break;
                    case "duration":
                        out.println(totalDuration());
                        break;
                    case "display":
                        display(out);
                        break;
                }
            }
            clear();
        }
        out.flush();
    }
}

