import sys
class Playlist:
    songs = []
    @classmethod
    def add_song(cls, title, artist, duration):
        cls.songs.append({"title": title, "artist": artist, "duration": duration})
    @classmethod
    def remove_song(cls, title):
        cls.songs = [s for s in cls.songs if s["title"] != title]
    @classmethod
    def get_total_duration(cls):
        return sum(s["duration"] for s in cls.songs)
    @classmethod
    def display_playlist(cls, out):
        for i, s in enumerate(cls.songs, 1):
            m, sec = divmod(s["duration"], 60)
            out.append(f"{i}. {s['title']} by {s['artist']} - {m}:{sec:02d}")
    @classmethod
    def clear(cls):
        cls.songs.clear()

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx].strip()); idx += 1
    out = []
    for _ in range(T):
        while idx < len(data):
            cmd = data[idx].strip(); idx += 1
            if cmd == "exit":
                break
            if cmd == "add":
                title, artist, dur = data[idx].strip().split(';'); idx += 1
                Playlist.add_song(title, artist, int(dur))
            elif cmd == "remove":
                title = data[idx].strip(); idx += 1
                Playlist.remove_song(title)
            elif cmd == "duration":
                out.append(str(Playlist.get_total_duration()))
            elif cmd == "display":
                Playlist.display_playlist(out)
        Playlist.clear()
    sys.stdout.write("\n".join(out))
if __name__ == "__main__":
    main()

