const fs = require('fs');
const lines = fs.readFileSync(0,'utf-8').trim().split(/\n/);
let idx = 0;
const T = parseInt(lines[idx++].trim(),10);
let output = [];
class Playlist {
  static songs = [];
  static addSong(title, artist, duration){
    this.songs.push({title, artist, duration});
  }
  static removeSong(title){
    this.songs = this.songs.filter(s=>s.title!==title);
  }
  static totalDuration(){
    return this.songs.reduce((a,s)=>a+s.duration,0);
  }
  static display(){
    this.songs.forEach((s,i)=>{
      const m = Math.floor(s.duration/60);
      const sec = s.duration%60;
      output.push(`${i+1}. ${s.title} by ${s.artist} - ${m}:${sec.toString().padStart(2,'0')}`);
    });
  }
  static clear(){ this.songs = []; }
}
for(let t=0;t<T;t++){
  while(idx < lines.length){
    const cmd = lines[idx++].trim();
    if(cmd === 'exit') break;
    if(cmd === 'add'){
      const [title,artist,dur] = lines[idx++].trim().split(';');
      Playlist.addSong(title,artist,parseInt(dur,10));
    } else if(cmd === 'remove'){
      const title = lines[idx++].trim();
      Playlist.removeSong(title);
    } else if(cmd === 'duration'){
      output.push(String(Playlist.totalDuration()));
    } else if(cmd === 'display'){
      Playlist.display();
    }
  }
  Playlist.clear();
}
